export function decodeJwt(token) {
  try {
    const parts = token.split('.');
    if (parts.length !== 3) {
      throw new Error('Invalid JWT format');
    }
    const header = JSON.parse(atob(parts[0].replace(/-/g, '+').replace(/_/g, '/')));
    const payload = JSON.parse(atob(parts[1].replace(/-/g, '+').replace(/_/g, '/')));
    return { header, payload, signature: parts[2] };
  } catch (error) {
    console.error('Failed to decode JWT:', error);
    return null;
  }
}

export function isTokenExpired(token) {
  const decoded = decodeJwt(token);
  if (!decoded || !decoded.payload.exp) return true;
  const now = Math.floor(Date.now() / 1000);
  return decoded.payload.exp < now;
}

export function extractUserProfile(idToken) {
  const decoded = decodeJwt(idToken);
  if (!decoded) return null;

  const { payload } = decoded;
  return {
    sub: payload.sub,
    name: payload.name || '',
    email: payload.email || '',
    emailVerified: payload.email_verified || false,
    picture: payload.picture || '',
    givenName: payload.given_name || '',
    familyName: payload.family_name || '',
    locale: payload.locale || '',
    issuedAt: payload.iat ? new Date(payload.iat * 1000) : null,
    expiresAt: payload.exp ? new Date(payload.exp * 1000) : null,
    issuer: payload.iss || '',
    audience: payload.aud || '',
    nonce: payload.nonce || '',
  };
}

export function validateIdToken(idToken, expectedNonce, clientId) {
  const decoded = decodeJwt(idToken);
  if (!decoded) {
    return { valid: false, error: 'Failed to decode token' };
  }

  const { payload } = decoded;

  if (isTokenExpired(idToken)) {
    return { valid: false, error: 'Token is expired' };
  }

  if (expectedNonce && payload.nonce !== expectedNonce) {
    return { valid: false, error: 'Nonce mismatch' };
  }

  const aud = Array.isArray(payload.aud) ? payload.aud : [payload.aud];
  if (clientId && !aud.includes(clientId)) {
    return { valid: false, error: 'Audience mismatch' };
  }

  return { valid: true, error: null };
}

