import React, { createContext, useContext, useReducer, useCallback, useEffect } from 'react';
import { oidcConfig } from '../config';
import { generateCodeVerifier, generateCodeChallenge, generateState, generateNonce } from '../utils/pkce';
import { extractUserProfile, validateIdToken, isTokenExpired } from '../utils/tokenUtils';

const AuthContext = createContext(null);

const initialState = {
  isAuthenticated: false,
  isLoading: true,
  user: null,
  accessToken: null,
  idToken: null,
  refreshToken: null,
  error: null,
};

function authReducer(state, action) {
  switch (action.type) {
    case 'LOGIN_START':
      return { ...state, isLoading: true, error: null };
    case 'LOGIN_SUCCESS':
      return {
        ...state,
        isAuthenticated: true,
        isLoading: false,
        user: action.payload.user,
        accessToken: action.payload.accessToken,
        idToken: action.payload.idToken,
        refreshToken: action.payload.refreshToken,
        error: null,
      };
    case 'LOGIN_ERROR':
      return {
        ...state,
        isAuthenticated: false,
        isLoading: false,
        user: null,
        accessToken: null,
        idToken: null,
        refreshToken: null,
        error: action.payload,
      };
    case 'LOGOUT':
      return { ...initialState, isLoading: false };
    case 'SET_LOADING':
      return { ...state, isLoading: action.payload };
    default:
      return state;
  }
}

export function AuthProvider({ children }) {
  const [state, dispatch] = useReducer(authReducer, initialState);

  useEffect(() => {
    const storedIdToken = sessionStorage.getItem('id_token');
    const storedAccessToken = sessionStorage.getItem('access_token');
    const storedRefreshToken = sessionStorage.getItem('refresh_token');

    if (storedIdToken && !isTokenExpired(storedIdToken)) {
      const user = extractUserProfile(storedIdToken);
      dispatch({
        type: 'LOGIN_SUCCESS',
        payload: {
          user,
          accessToken: storedAccessToken,
          idToken: storedIdToken,
          refreshToken: storedRefreshToken,
        },
      });
    } else {
      sessionStorage.removeItem('id_token');
      sessionStorage.removeItem('access_token');
      sessionStorage.removeItem('refresh_token');
      dispatch({ type: 'SET_LOADING', payload: false });
    }
  }, []);

  const login = useCallback(async () => {
    try {
      dispatch({ type: 'LOGIN_START' });

      const codeVerifier = await generateCodeVerifier();
      const codeChallenge = await generateCodeChallenge(codeVerifier);
      const stateParam = generateState();
      const nonce = generateNonce();

      sessionStorage.setItem('pkce_code_verifier', codeVerifier);
      sessionStorage.setItem('oauth_state', stateParam);
      sessionStorage.setItem('oauth_nonce', nonce);

      const params = new URLSearchParams({
        response_type: oidcConfig.responseType,
        client_id: oidcConfig.clientId,
        redirect_uri: oidcConfig.redirectUri,
        scope: oidcConfig.scope,
        state: stateParam,
        nonce: nonce,
        code_challenge: codeChallenge,
        code_challenge_method: 'S256',
        prompt: 'consent',
        access_type: 'offline',
      });

      const authUrl = `${oidcConfig.authorizationEndpoint}?${params.toString()}`;
      window.location.href = authUrl;
    } catch (error) {
      dispatch({ type: 'LOGIN_ERROR', payload: error.message });
    }
  }, []);

  const handleCallback = useCallback(async (searchParams) => {
    try {
      dispatch({ type: 'LOGIN_START' });

      const code = searchParams.get('code');
      const returnedState = searchParams.get('state');
      const error = searchParams.get('error');
      const errorDescription = searchParams.get('error_description');

      if (error) {
        throw new Error(`Authorization error: ${error} - ${errorDescription || ''}`);
      }

      if (!code) {
        throw new Error('No authorization code received');
      }

      const savedState = sessionStorage.getItem('oauth_state');
      if (returnedState !== savedState) {
        throw new Error('State parameter mismatch - possible CSRF attack');
      }

      const codeVerifier = sessionStorage.getItem('pkce_code_verifier');
      const savedNonce = sessionStorage.getItem('oauth_nonce');

      if (!codeVerifier) {
        throw new Error('No code verifier found');
      }

      const tokenResponse = await exchangeCodeForTokens(code, codeVerifier);

      sessionStorage.removeItem('pkce_code_verifier');
      sessionStorage.removeItem('oauth_state');
      sessionStorage.removeItem('oauth_nonce');

      const { id_token, access_token, refresh_token } = tokenResponse;

      if (!id_token) {
        throw new Error('No id_token in token response');
      }

      const validation = validateIdToken(id_token, savedNonce, oidcConfig.clientId);
      if (!validation.valid) {
        throw new Error(`Token validation failed: ${validation.error}`);
      }

      const user = extractUserProfile(id_token);

      sessionStorage.setItem('id_token', id_token);
      sessionStorage.setItem('access_token', access_token);
      if (refresh_token) {
        sessionStorage.setItem('refresh_token', refresh_token);
      }

      dispatch({
        type: 'LOGIN_SUCCESS',
        payload: {
          user,
          accessToken: access_token,
          idToken: id_token,
          refreshToken: refresh_token || null,
        },
      });

      return user;
    } catch (error) {
      dispatch({ type: 'LOGIN_ERROR', payload: error.message });
      throw error;
    }
  }, []);

  const logout = useCallback(() => {
    sessionStorage.removeItem('id_token');
    sessionStorage.removeItem('access_token');
    sessionStorage.removeItem('refresh_token');
    sessionStorage.removeItem('pkce_code_verifier');
    sessionStorage.removeItem('oauth_state');
    sessionStorage.removeItem('oauth_nonce');

    dispatch({ type: 'LOGOUT' });

    const params = new URLSearchParams({
      post_logout_redirect_uri: oidcConfig.postLogoutRedirectUri,
    });

    window.location.href = `${oidcConfig.authority}/logout?${params.toString()}`;
  }, []);

  const value = {
    ...state,
    login,
    logout,
    handleCallback,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

async function exchangeCodeForTokens(code, codeVerifier) {
  const body = new URLSearchParams({
    grant_type: 'authorization_code',
    code: code,
    redirect_uri: oidcConfig.redirectUri,
    client_id: oidcConfig.clientId,
    code_verifier: codeVerifier,
  });

  const response = await fetch(oidcConfig.tokenEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: body.toString(),
  });

  if (!response.ok) {
    const errorData = await response.json().catch(() => ({}));
    throw new Error(
      `Token exchange failed: ${response.status} - ${errorData.error_description || errorData.error || 'Unknown error'}`
    );
  }

  return response.json();
}

